def dots_and_boxes_optimal(rows, cols, moves):
    R, C = rows, cols
    num_h = (R + 1) * C
    num_v = R * (C + 1)
    num_edges = num_h + num_v

    box_masks = []
    for br in range(R):
        for bc in range(C):
            top = br * C + bc
            bottom = (br + 1) * C + bc
            left = num_h + br * (C + 1) + bc
            right = num_h + br * (C + 1) + bc + 1
            box_masks.append((1 << top) | (1 << bottom) | (1 << left) | (1 << right))

    num_boxes = len(box_masks)
    all_edges = (1 << num_edges) - 1

    drawn = 0
    p1_score, p2_score = 0, 0
    p1_turn = True

    for e in moves:
        prev = drawn
        drawn |= (1 << e)
        completed = 0
        for i in range(num_boxes):
            if (drawn & box_masks[i]) == box_masks[i] and (prev & box_masks[i]) != box_masks[i]:
                completed += 1
        if completed > 0:
            if p1_turn:
                p1_score += completed
            else:
                p2_score += completed
        else:
            p1_turn = not p1_turn

    from functools import lru_cache
    bm = tuple(box_masks)

    @lru_cache(maxsize=None)
    def solve(drawn_mask, is_p1):
        if drawn_mask == all_edges:
            return 0
        best = float('-inf') if is_p1 else float('inf')
        remaining = all_edges ^ drawn_mask
        bits = remaining
        while bits:
            bit = bits & (-bits)
            nd = drawn_mask | bit
            cnt = 0
            for m in bm:
                if (nd & m) == m and (drawn_mask & m) != m:
                    cnt += 1
            if cnt > 0:
                delta = cnt if is_p1 else -cnt
                val = delta + solve(nd, is_p1)
            else:
                val = solve(nd, not is_p1)
            if is_p1:
                if val > best:
                    best = val
            else:
                if val < best:
                    best = val
            bits ^= bit
        return best

    future = solve(drawn, p1_turn)
    return (p1_score - p2_score) + future

