import unittest

class TestDotsAndBoxes(unittest.TestCase):
    def test_1x1_empty(self):
        # 1x1 box: 4 edges, P2 always gets the last (completing) move
        self.assertEqual(dots_and_boxes_optimal(1, 1, []), -1)

    def test_1x1_one_remaining(self):
        # 3 edges drawn, P2 completes the box
        self.assertEqual(dots_and_boxes_optimal(1, 1, [0, 1, 2]), -1)

    def test_1x2_empty(self):
        # 1x2 box grid: P1 can draw shared edge first to force a tie
        self.assertEqual(dots_and_boxes_optimal(1, 2, []), 0)

    def test_hidden_1x1_complete(self):
        # All moves played: replay gives P2 the completing move
        self.assertEqual(dots_and_boxes_optimal(1, 1, [3, 2, 1, 0]), -1)

    def test_hidden_2x2_empty(self):
        # Full 2x2 game from scratch with optimal play
        self.assertEqual(dots_and_boxes_optimal(2, 2, []), 0)

    def test_hidden_double_completion(self):
        # Only edge 10 remains; it completes TWO boxes for P2
        self.assertEqual(dots_and_boxes_optimal(2, 2, [6, 8, 0, 1, 2, 7, 3, 9, 4, 5, 11]), -4)

    def test_hidden_2x2_endgame(self):
        # P1 gets to complete the last 2 boxes in a chain
        self.assertEqual(dots_and_boxes_optimal(2, 2, [6, 8, 0, 1, 9, 5, 2, 7, 3, 10]), 0)

    def test_hidden_1x2_partial(self):
        # P2 exploits P1's exposed 3-edge box to chain both boxes
        self.assertEqual(dots_and_boxes_optimal(1, 2, [0, 1, 4, 6, 2]), -2)

if __name__ == '__main__':
    unittest.main()
